using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip default RenderMode changed from
        // System to ManagerRenderMode (Professional). Set explicitly to keep
        // the .NET 8 visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    // .NET 9 breaking change: IWindowsFormsEditorService.DropDownControl now
    // throws ArgumentNullException when passed null. Guard all call sites.
    public static void SafeDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

